@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <small class="text-muted ms-2">@notification.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? Notifications { get; set; }

    private List<Notification> notifications => Notifications ?? new();

    private CancellationTokenSource? _cts;
    private int _lastId;

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not already restored from prerender state
        Notifications ??= await NotificationService.GetNotificationsAsync();
        _lastId = Notifications.Count > 0 ? Notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Start polling only after the page is interactive (never during prerender)
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(5000, cancellationToken);

            var newItems = await NotificationService.GetNotificationsSinceAsync(_lastId);
            if (newItems.Count > 0)
            {
                Notifications!.AddRange(newItems);
                _lastId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

