 @code {
     [PersistentState]
     public List<Notification>? StoredNotifications { get; set; }

     private List<Notification> notifications => StoredNotifications ?? new();

     private CancellationTokenSource? _cts;
     private int _lastId;

     protected override async Task OnInitializedAsync()
     {
         // Only fetch if not already restored from prerender state
         StoredNotifications ??= await NotificationService.GetNotificationsAsync();
         _lastId = StoredNotifications.Count > 0 ? StoredNotifications.Max(n => n.Id) : 0;
     }

     protected override void OnAfterRender(bool firstRender)
     {
         if (firstRender)
         {
             // Start polling only after the page is interactive (never during prerender)
             _cts = new CancellationTokenSource();
             _ = PollForNotificationsAsync(_cts.Token);
         }
     }

     private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
     {
         while (!cancellationToken.IsCancellationRequested)
         {
             await Task.Delay(5000, cancellationToken);

             var newItems = await NotificationService.GetNotificationsSinceAsync(_lastId);
             if (newItems.Count > 0)
             {
                 StoredNotifications!.AddRange(newItems);
                 _lastId = newItems.Max(n => n.Id);
                 await InvokeAsync(StateHasChanged);
             }
         }
     }

     public async ValueTask DisposeAsync()
     {
         if (_cts is not null)
         {
             await _cts.CancelAsync();
             _cts.Dispose();
         }
     }
 }
